; [AI] Prints a null-terminated string pointed to by HL one character at a time via the console-
;       output helper; the standard message-printing routine.
SUB_04A2:
        LD A,(HL)                        ; $04A2  7E
L_04A3:
        OR A                             ; $04A3  B7
L_04A4:
